code.C++:
string solve(int N, int X, const vector<int>& A) {
    for (int i = 0; i < N; i++) {
        if (A[i] == X) {
            return "YES";
        }
    }
    return "NO";
}

code.Python3:
def solve(N, X, A):
    if X in A:
        return "YES"
    else:
        return "NO"

